var e=[{id:`L2_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`저 실험체가 당했다고? 이건…… 있을 수 없는 일이야.`,JPN:`実験体がやられただと？　こんなこと……ありえない。`,ENG:`Did they really beat that test subject? This is... unbelievable!`,TWN:`那個實驗體竟然輸了？這……這怎麼可能！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`빌어먹을 자식들. 너희가 지금 무슨 짓을 하는지 알아?`,JPN:`クソども……お前らが今何をしているのかわかってるのか！`,ENG:`You dratted fools, do you even know what you're doing?`,TWN:`該死的傢伙！你們知道你們在做什麼嗎！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`그러는 당신은 지금 나한테 죽을 수도 있다는 걸 알고 있으려나?`,JPN:`そういうあなたは、今自分が殺されるかもしれないってことはわかってるのかしら。`,ENG:`Do you know I can kill you right now?`,TWN:`那你又知道你很快就會死在我手裡嗎？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`……그, 그깟 시한부 인생을 구하겠다고 이런 짓을 벌이다니.`,JPN:`……ど、どうせそろそろ死ぬ奴のためにここまでするとは。`,ENG:`I-I can't believe you're doing this to save her when she doesn't have much longer to live.`,TWN:`……她再活也沒多久，值得你們這樣大費周章來救她嗎？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`대가를 치르게 해줄 테니 두고 보라고!`,JPN:`代償を払わせてやる！　今に見てろ！`,ENG:`You'll pay for it. You'll see!`,TWN:`給我等著瞧吧！我一定會讓你們付出代價！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`어라, 그쪽으로 나가면 안 될 텐데.`,JPN:`あら、そっちから出るとまずいわよ。`,ENG:`Err, you shouldn't go out that way.`,TWN:`哈囉～走那邊不太OK喔？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`헉…… 헉.`,JPN:`はっ……はっ。`,ENG:`Huff... Huff...`,TWN:`呼……呼…`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`더 이상 쫓아오지 않는 건가?`,JPN:`もう追いかけてこないのか？`,ENG:`I don't think they're following me anymore.`,TWN:`應該沒追上來了吧？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`음?`,JPN:`あ？`,ENG:`Mm?`,TWN:`嗯？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`손 들고 무릎 꿇어.`,JPN:`手を上げて跪け。`,ENG:`Raise your hands and kneel.`,TWN:`雙手舉高跪下。`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`다, 당신들 뭐야……?`,JPN:`お、お前らは何者だ……？`,ENG:`Wh-who are you?`,TWN:`你…你們又是誰……？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`너 같은 놈들 때문에 우리가 눈을 못 감는다니까.`,JPN:`お前みたいな奴らのせいで我々が安らかに眠れないんだ。`,ENG:`We can't rest because of people like you.`,TWN:`都是你這傢伙害我們沒得睡！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`뭐 해?`,JPN:`何をしている？`,ENG:`What are you doing?`,TWN:`幹嘛？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`RIFLE_ADMIN_NAMED_NULL`,text:{KOREA:`어물쩍거릴 때마다 총탄 한 발이다.`,JPN:`もたもたするたびに一発だ。`,ENG:`Do as I say or eat a bullet.`,TWN:`你敢亂動我就讓你變蜂窩！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_TOUCH`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`DIRECTOR_NPC_BARCODE_NULL`,text:{KOREA:`히익! 항복! 항복하겠습니다!`,JPN:`ひいっ！　降伏！　降伏します！`,ENG:`Heek! Surrender! I surrender!`,TWN:`唔！我投降！別殺我！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`RIFLE_ADMIN_NAMED_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`하아…… 하……`,JPN:`はあ……はぁ……`,ENG:`Haaah... Hah...`,TWN:`呼……呼……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`GAEUN_HB_NULL_NULL`,text:{KOREA:`손, 잡을 수 있겠어?`,JPN:`手、握れそう？`,ENG:`Can you hold my hand?`,TWN:`我…可以握你的手嗎？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GAEUN_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`LUCID_BARCODE_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GAEUN_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};